import os
import requests
from PIL import Image
from sklearn.model_selection import train_test_split
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Dense, Flatten
from tensorflow.keras.optimizers import Adam
from tensorflow.keras.utils import to_categorical
import numpy as np

class DataLabelingSystem:
    def __init__(self, api_url):
        self.api_url = api_url
        self.labeled_data = {}
        self.model = None

    def annotate(self, annotator_id, image_path, label):
        response = requests.post(f"{self.api_url}/annotate", 
                                 json={"annotator_id": annotator_id, 
                                       "image_path": image_path, 
                                       "label": label})
        if response.status_code == 200:
            self.labeled_data[image_path] = self.labeled_data.get(image_path, []) + [label]
            return True
        else:
            print(f"Error annotating: {response.text}")
            return False

    def aggregate_labels(self):
        for image_path, labels in self.labeled_data.items():
            unique_labels = set(labels)
            max_count = 0
            most_common_label = None
            for label in unique_labels:
                count = labels.count(label)
                if count > max_count:
                    max_count = count
                    most_common_label = label
            self.labeled_data[image_path] = [most_common_label]

    def train_model(self):
        images = []
        labels = []
        for image_path, label in self.labeled_data.items():
            img = Image.open(image_path)
            img = np.array(img) / 255.0
            images.append(img)
            labels.append(label)

        X_train, X_test, y_train, y_test = train_test_split(images, labels, test_size=0.2, random_state=42)
        X_train = np.array(X_train).reshape(-1, 224, 224, 3)
        X_test = np.array(X_test).reshape(-1, 224, 224, 3)

        model = Sequential()
        model.add(Flatten(input_shape=(224, 224, 3)))
        model.add(Dense(128, activation="relu"))
        model.add(Dense(len(set(y_train)), activation="softmax"))

        model.compile(loss="sparse_categorical_crossentropy", optimizer=Adam(), metrics=["accuracy"])
        model.fit(X_train, to_categorical(y_train), epochs=10)

        self.model = model

# Usage example:
if __name__ == "__main__":
    labeling_system = DataLabelingSystem("http://localhost:8000/api")
    labeling_system.annotate("annotator1", "path/to/image.jpg", 1)
    labeling_system.annotate("annotator2", "path/to/image.jpg", 1)
    labeling_system.aggregate_labels()
    labeling_system.train_model()